const body = $input.first().json.body || $input.first().json;
const staticData = $getWorkflowStaticData('global');

if (!staticData.failedAuthLog) staticData.failedAuthLog = [];
if (!staticData.blacklist) staticData.blacklist = {};

const entry = {
  ip:        body.ip        || 'unknown',
  sessionId: body.sessionId || 'unknown',
  timestamp: new Date().toISOString(),
  reason:    body.reason    || 'unknown',
  userAgent: body.userAgent || ''
  // NOTE: message content is intentionally NOT logged (privacy)
};

staticData.failedAuthLog.push(entry);

// Keep last 1000 entries
if (staticData.failedAuthLog.length > 1000) {
  staticData.failedAuthLog = staticData.failedAuthLog.slice(-1000);
}

// Check if IP should be blacklisted (>10 fails in 1 hour)
const ONE_HOUR_AGO = Date.now() - 3600000;
const recentFails = staticData.failedAuthLog.filter(
  e => e.ip === entry.ip && new Date(e.timestamp).getTime() > ONE_HOUR_AGO
);

if (recentFails.length >= 10) {
  staticData.blacklist[entry.ip] = {
    blockedAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + 86400000).toISOString() // 24h
  };
}

return [{ json: { logged: true, total_fails: staticData.failedAuthLog.length } }];
